import time
import random
from enum import Enum
from typing import Callable, TypeVar, Optional
from dataclasses import dataclass

T = TypeVar('T')

class ErrorSeverity(Enum):
    TRANSIENT = "transient"      # Retry immediately
    RATE_LIMITED = "rate_limited" # Retry with backoff
    DEGRADED = "degraded"        # Use fallback
    FATAL = "fatal"              # Abort and report

@dataclass
class AgentError(Exception):
    message: str
    severity: ErrorSeverity
    tool_name: Optional[str] = None
    original_error: Optional[Exception] = None
    retry_count: int = 0

class ToolTimeoutError(AgentError):
    def __init__(self, tool_name: str, timeout_seconds: float):
        super().__init__(
            message=f"Tool '{tool_name}' timed out after {timeout_seconds}s",
            severity=ErrorSeverity.TRANSIENT,
            tool_name=tool_name
        )

class RateLimitError(AgentError):
    def __init__(self, tool_name: str, retry_after: Optional[int] = None):
        super().__init__(
            message=f"Rate limit hit for '{tool_name}'",
            severity=ErrorSeverity.RATE_LIMITED,
            tool_name=tool_name
        )
        self.retry_after = retry_after

class MalformedOutputError(AgentError):
    def __init__(self, tool_name: str, raw_output: str):
        super().__init__(
            message=f"Tool '{tool_name}' returned unparseable output",
            severity=ErrorSeverity.DEGRADED,
            tool_name=tool_name
        )
        self.raw_output = raw_output

def with_retry(
    func: Callable[[], T],
    max_retries: int = 3,
    base_delay: float = 1.0,
    max_delay: float = 60.0,
    jitter: bool = True
) -> T:
    """Execute a function with exponential backoff retry logic."""
    last_error = None

    for attempt in range(max_retries + 1):
        try:
            return func()
        except AgentError as e:
            last_error = e
            e.retry_count = attempt

            if e.severity == ErrorSeverity.FATAL:
                raise  # Never retry fatal errors

            if attempt == max_retries:
                break

            # Calculate delay based on error type
            if e.severity == ErrorSeverity.RATE_LIMITED:
                delay = getattr(e, 'retry_after', None) or (
                    base_delay * (2 ** attempt)
                )
            elif e.severity == ErrorSeverity.TRANSIENT:
                delay = base_delay * (2 ** attempt)
            else:
                raise  # DEGRADED errors go to fallback, not retry

            if jitter:
                delay *= (0.5 + random.random())

            delay = min(delay, max_delay)
            print(f"[Retry {attempt + 1}/{max_retries}] "
                  f"Waiting {delay:.2f}s after: {e.message}")
            time.sleep(delay)

    raise last_error

