from pydantic import BaseModel, ValidationError, field_validator
from typing import Any, Optional, Type
import json
import re

class ToolCallOutput(BaseModel):
    status: str
    data: dict
    confidence: float
    source_url: Optional[str] = None

    @field_validator('status')
    @classmethod
    def status_must_be_valid(cls, v):
        if v not in ('success', 'partial', 'error'):
            raise ValueError(f"Invalid status: {v}")
        return v

    @field_validator('confidence')
    @classmethod
    def confidence_in_range(cls, v):
        if not 0.0 <= v <= 1.0:
            raise ValueError(f"Confidence must be 0-1, got {v}")
        return v

def extract_json_from_llm_output(raw: str) -> Optional[dict]:
    """Attempt to extract JSON even from poorly formatted LLM output."""
    # Try direct parse first
    try:
        return json.loads(raw)
    except json.JSONDecodeError:
        pass

    # Try extracting JSON block from markdown
    json_pattern = r'```(?:json)?\s*([\s\S]*?)```'
    matches = re.findall(json_pattern, raw)
    for match in matches:
        try:
            return json.loads(match.strip())
        except json.JSONDecodeError:
            continue

    # Try finding bare JSON object
    brace_pattern = r'\{[\s\S]*\}'
    matches = re.findall(brace_pattern, raw)
    for match in matches:
        try:
            return json.loads(match)
        except json.JSONDecodeError:
            continue

    return None

def validate_tool_output(
    raw_output: str,
    schema: Type[BaseModel],
    tool_name: str,
    llm_repair_func=None  # Optional: pass LLM callable for repair
) -> BaseModel:
    """
    Validate tool output against schema with progressive repair attempts.
    """
    # Step 1: Try to extract JSON
    parsed = extract_json_from_llm_output(raw_output)

    if parsed is None:
        if llm_repair_func:
            repair_prompt = (
                f"The following output from tool '{tool_name}' is not valid JSON. "
                f"Convert it to valid JSON matching this schema: {schema.model_json_schema()}\n"
                f"Output to repair:\n{raw_output}\n"
                f"Return ONLY the JSON object, no explanation."
            )
            repaired = llm_repair_func(repair_prompt)
            parsed = extract_json_from_llm_output(repaired)

        if parsed is None:
            raise MalformedOutputError(
                tool_name=tool_name,
                raw_output=raw_output
            )

    # Step 2: Validate against schema
    try:
        return schema(**parsed)
    except ValidationError as e:
        error_summary = "; ".join(
            f"{err['loc']}: {err['msg']}" 
            for err in e.errors()
        )
        raise MalformedOutputError(
            tool_name=tool_name,
            raw_output=f"Schema validation failed: {error_summary}"
        )

# Usage
raw = '{"status": "success", "data": {"temp": 72}, "confidence": 0.95}'
try:
    validated = validate_tool_output(raw, ToolCallOutput, "weather_api")
    print(f"Validated output: {validated}")
except MalformedOutputError as e:
    print(f"Output validation failed: {e.message}")

import time
from enum import Enum
from collections import deque
from threading import Lock
from typing import Callable, Optional
from dataclasses import dataclass, field

class CircuitState(Enum):
    CLOSED = "closed"       # Normal operation
    OPEN = "open"           # Failing, reject calls
    HALF_OPEN = "half_open" # Testing recovery

@dataclass
class CircuitBreakerConfig:
    failure_threshold: int = 5      # Failures before opening
    success_threshold: int = 2      # Successes to close from half-open
    timeout_seconds: float = 60.0   # Time before trying half-open
    window_seconds: float = 120.0   # Rolling window for failure counting

class CircuitBreaker:
    def __init__(self, name: str, config: CircuitBreakerConfig = None):
        self.name = name
        self.config = config or CircuitBreakerConfig()
        self.state = CircuitState.CLOSED
        self.failure_times: deque = deque()
        self.consecutive_successes = 0
        self.last_failure_time: Optional[float] = None
        self._lock = Lock()

    def _prune_old_failures(self):
        """Remove failures outside the rolling window."""
        cutoff = time.time() - self.config.window_seconds
        while self.failure_times and self.failure_times[0] < cutoff:
            self.failure_times.popleft()

    def _recent_failure_count(self) -> int:
        self._prune_old_failures()
        return len(self.failure_times)

    def call(self, func: Callable, *args, **kwargs):
        """Execute function through circuit breaker."""
        with self._lock:
            if self.state == CircuitState.OPEN:
                elapsed = time.time() - (self.last_failure_time or 0)
                if elapsed >= self.config.timeout_seconds:
                    print(f"[CircuitBreaker:{self.name}] "
                          f"Transitioning to HALF_OPEN")
                    self.state = CircuitState.HALF_OPEN
                    self.consecutive_successes = 0
                else:
                    remaining = self.config.timeout_seconds - elapsed
                    raise AgentError(
                        message=f"Circuit breaker OPEN for '{self.name}'. "
                                f"Retry in {remaining:.0f}s",
                        severity=ErrorSeverity.DEGRADED,
                        tool_name=self.name
                    )

        try:
            result = func(*args, **kwargs)
            self._on_success()
            return result
        except Exception as e:
            self._on_failure()
            raise

    def _on_success(self):
        with self._lock:
            if self.state == CircuitState.HALF_OPEN:
                self.consecutive_successes += 1
                if self.consecutive_successes >= self.config.success_threshold:
                    print(f"[CircuitBreaker:{self.name}] "
                          f"Recovered, transitioning to CLOSED")
                    self.state = CircuitState.CLOSED
                    self.failure_times.clear()
            elif self.state == CircuitState.CLOSED:
                self.consecutive_successes += 1

    def _on_failure(self):
        with self._lock:
            self.failure_times.append(time.time())
            self.last_failure_time = time.time()
            self.consecutive_successes = 0

            if self._recent_failure_count() >= self.config.failure_threshold:
                if self.state != CircuitState.OPEN:
                    print(f"[CircuitBreaker:{self.name}] "
                          f"Threshold exceeded, OPENING circuit")
                    self.state = CircuitState.OPEN

    @property
    def status(self) -> dict:
        return {
            "name": self.name,
            "state": self.state.value,
            "recent_failures": self._recent_failure_count(),
            "consecutive_successes": self.consecutive_successes
        }

# Tool registry with circuit breakers
class ToolRegistry:
    def __init__(self):
        self._breakers: dict[str, CircuitBreaker] = {}

    def get_breaker(self, tool_name: str) -> CircuitBreaker:
        if tool_name not in self._breakers:
            self._breakers[tool_name] = CircuitBreaker(tool_name)
        return self._breakers[tool_name]

    def call_tool(self, tool_name: str, func: Callable, *args, **kwargs):
        breaker = self.get_breaker(tool_name)
        return breaker.call(func, *args, **kwargs)

    def health_report(self) -> list[dict]:
        return [b.status for b in self._breakers.values()]

