from typing import Callable, Any, Optional
from dataclasses import dataclass
import logging

logger = logging.getLogger(__name__)

@dataclass
class FallbackResult:
    value: Any
    source: str          # Which strategy succeeded
    degraded: bool       # True if not the primary strategy
    attempts: list[str]  # All strategies attempted

class FallbackChain:
    """
    Defines an ordered chain of strategies for a capability.
    Falls through to the next strategy on failure.
    """

    def __init__(self, capability_name: str):
        self.capability_name = capability_name
        self._strategies: list[tuple[str, Callable]] = []

    def add_strategy(
        self, 
        name: str, 
        func: Callable,
        is_primary: bool = False
    ) -> 'FallbackChain':
        """Add a strategy. Primary strategies go first."""
        if is_primary:
            self._strategies.insert(0, (name, func))
        else:
            self._strategies.append((name, func))
        return self

    def execute(self, *args, **kwargs) -> FallbackResult:
        """Execute strategies in order until one succeeds."""
        attempted = []
        last_error = None

        for i, (name, strategy) in enumerate(self._strategies):
            attempted.append(name)
            is_primary = (i == 0)

            try:
                result = strategy(*args, **kwargs)

                if not is_primary:
                    logger.warning(
                        f"[{self.capability_name}] Degraded to fallback "
                        f"strategy '{name}' after failing: "
                        f"{[s for s in attempted[:-1]]}"
                    )

                return FallbackResult(
                    value=result,
                    source=name,
                    degraded=not is_primary,
                    attempts=attempted
                )

            except Exception as e:
                last_error = e
                logger.warning(
                    f"[{self.capability_name}] Strategy '{name}' failed: "
                    f"{type(e).__name__}: {e}"
                )
                continue

        # All strategies exhausted
        raise AgentError(
            message=f"All fallback strategies exhausted for "
                    f"'{self.capability_name}'. "
                    f"Tried: {attempted}",
            severity=ErrorSeverity.FATAL,
            original_error=last_error
        )

