def cached_search(query: str) -> dict:
    """Return cached results - may be stale."""
    return {
        "results": ["cached_result_1"],
        "cached": True,
        "cache_age_hours": 4
    }

def llm_knowledge_fallback(query: str) -> dict:
    """Use LLM's parametric knowledge as last resort."""
    return {
        "results": [f"LLM knowledge response for: {query}"],
        "from_parametric_knowledge": True,
        "confidence": 0.6
    }

# Build the fallback chain
search_chain = (
    FallbackChain("web_search")
    .add_strategy("primary_api", primary_search_api, is_primary=True)
    .add_strategy("secondary_api", secondary_search_api)
    .add_strategy("cache", cached_search)
    .add_strategy("llm_knowledge", llm_knowledge_fallback)
)

# Execute with automatic fallback
try:
    result = search_chain.execute("latest AI agent frameworks")

    if result.degraded:
        print(f"⚠️  Using degraded source: {result.source}")
        print(f"   Failed strategies: {result.attempts[:-1]}")
    else:
        print(f"✓ Primary strategy succeeded")

    print(f"Result: {result.value}")

except AgentError as e:
    print(f"Complete failure: {e.message}")
